-- Generated by scripts/gen-seed.mjs — do not edit by hand.
-- Seeds the shared experiment library. Safe to re-run (upsert on id).

insert into public.experiments (id, data) values
  ('density-column', '{"id":"density-column","title":"Liquid Density Column","summary":"Stack four household liquids in a clear glass to reveal that liquids have different densities and arrange themselves heaviest on the bottom.","grade_level":"9-10","duration_minutes":20,"learning_goals":["Define density as mass per unit volume.","Predict the order of layers from densest to least dense.","Explain why liquids that do not mix form stable layers."],"materials":[{"name":"Tall clear glass or jar","quantity":"1","notes":"Straight sides make layers easier to see."},{"name":"Honey","quantity":"about 2 tablespoons"},{"name":"Dish soap (any color)","quantity":"about 2 tablespoons"},{"name":"Water","quantity":"about 2 tablespoons","notes":"Add a drop of food coloring if you have it, to see the layer clearly."},{"name":"Vegetable or olive oil","quantity":"about 2 tablespoons"},{"name":"Spoon","quantity":"1","notes":"Used to pour gently against the side of the glass."}],"safety":["Work over a tray or paper towels — drips happen.","Do not drink the column.","Wash hands after handling dish soap."],"steps":[{"id":"setup","instruction":"Place the empty glass on a flat surface with your four liquids lined up next to it: honey, dish soap, water, and oil. Have a spoon ready.","checkpoint":{"expected_state":"An empty clear glass on a flat surface, with four containers of liquid (honey, dish soap, water, oil) visible nearby and a spoon present.","success_criteria":["Exactly one clear glass is visible and it is empty.","At least three of the four expected liquids are visible near the glass.","A spoon is visible in the frame."],"failure_hints":["If the glass already has liquid in it, empty and rinse it before starting.","If you cannot see all the liquids, slide them closer to the camera so the assistant can confirm they are there."]},"simulation":{"observation":"You see an empty glass and four containers: a thick golden honey, a colored dish soap, water, and yellow oil.","tutor_prompts":["Before we pour anything, which of these four liquids do you think is the densest? Why?","Which do you think will end up on top of the column, and what makes you say that?"]}},{"id":"pour-honey","instruction":"Pour the honey straight down into the center of the glass. Try not to let it touch the sides on the way down.","checkpoint":{"expected_state":"The glass now has a single layer of honey at the bottom, roughly one-quarter to one-third full, with clean glass walls above it.","success_criteria":["A thick amber-colored layer is visible at the bottom of the glass.","The walls of the glass above the honey are not heavily coated.","No other liquid has been added yet."],"failure_hints":["If honey is smeared up the sides, that''s fine — it will settle. Wait a few seconds before the next pour.","If the honey layer looks tiny, you can add a little more before moving on."]},"simulation":{"observation":"The honey settles slowly into a thick amber layer at the bottom of the glass.","tutor_prompts":["Honey is mostly sugar dissolved in a little water. How would dissolving lots of sugar change the density compared to plain water?","Why do you think the honey is moving so slowly compared to how water would pour?"]}},{"id":"pour-soap","instruction":"Now tilt the glass slightly and pour the dish soap gently down the inside wall of the glass so it lands on top of the honey without splashing through it.","checkpoint":{"expected_state":"Two distinct layers are visible: honey on the bottom and dish soap resting above it, separated by a clear boundary.","success_criteria":["Two separate colored layers are visible inside the glass.","The boundary between the layers is roughly horizontal.","The layers have not mixed into a single murky color."],"failure_hints":["If the layers mixed, that usually means the soap was poured too fast or from too high. Let things settle for thirty seconds and look again — they often re-separate.","If you see only one layer, check whether the dish soap actually made it into the glass."]},"simulation":{"observation":"A second colored layer sits cleanly on top of the honey, with a visible flat boundary between them.","tutor_prompts":["The soap is sitting on the honey instead of sinking into it. What does that tell you about the soap''s density compared to honey''s?","What do you predict will happen when we pour water in next?"]}},{"id":"pour-water","instruction":"Slowly pour the water down the inside wall of the glass on top of the dish soap. Go gently — the water layer is the easiest one to break.","checkpoint":{"expected_state":"Three layers are now visible: honey on the bottom, dish soap in the middle, and water on top.","success_criteria":["Three separate horizontal layers are visible.","The water layer sits clearly on top of the soap layer, not mixed into it.","The original honey layer at the bottom is still intact."],"failure_hints":["If the water punched through the soap, pause for a minute — sometimes it floats back up.","If the water and soap have visibly mixed, that''s still a valid result — note what happened before continuing."]},"simulation":{"observation":"A clear (or lightly colored) water layer rests on top of the dish soap. You can count three distinct bands now.","tutor_prompts":["Rank the three liquids you''ve poured so far from densest to least dense based on what you see.","Water is denser than oil but less dense than dish soap. What does that tell you about the structure of soap versus oil?"]}},{"id":"pour-oil","instruction":"Finally, pour the oil slowly on top of the water. You should now see four layers.","checkpoint":{"expected_state":"A finished density column with four visible layers, from bottom to top: honey, dish soap, water, oil.","success_criteria":["Four distinct horizontal layers are visible.","The top layer is a translucent yellow oil.","No layer is obviously inverted from the expected order."],"failure_hints":["If you only count three layers, check whether the water and oil merged — they should not.","If the column looks cloudy, give it a minute to settle and try again."]},"simulation":{"observation":"Four bands of color stack neatly in the glass: amber honey, colored soap, water, and a yellow oil layer on top.","tutor_prompts":["You correctly predicted some of the order. Which layer surprised you, and why?","If you very gently dropped a small object — say, a grape — into the column, where do you think it would stop, and why?"]}}],"reflection":["List the four liquids in order from densest to least dense.","Why do oil and water never mix into a single uniform layer, even if you stir them?","Name another pair of common liquids that you would expect to form layers and explain your reasoning."]}'::jsonb),
  ('saltwater-egg-float', '{"id":"saltwater-egg-float","title":"Salt, Water, and a Floating Egg","summary":"Discover why an egg sinks in fresh water but floats in salt water by adding salt one spoonful at a time until the egg lifts off the bottom.","grade_level":"8-10","duration_minutes":15,"learning_goals":["Connect density to whether an object sinks or floats.","Predict how dissolving salt changes the density of water.","Design a simple iterative test (add, observe, repeat)."],"materials":[{"name":"Tall clear glass or jar","quantity":"1","notes":"Tall enough that the egg is fully submerged."},{"name":"Fresh raw egg in its shell","quantity":"1"},{"name":"Tap water","quantity":"enough to fill the glass about 3/4"},{"name":"Table salt","quantity":"about 1/2 cup available","notes":"You usually need 4-8 tablespoons total."},{"name":"Spoon for stirring","quantity":"1"}],"safety":["Use a raw egg only in its shell. If it cracks, stop and clean up.","Do not drink the salt water.","Work over a tray to catch spills."],"steps":[{"id":"setup","instruction":"Fill the glass about three-quarters full with tap water. Place the empty spoon and the salt nearby.","checkpoint":{"expected_state":"A clear glass roughly three-quarters full of clear water, with a container of salt and a spoon visible nearby. The egg has not yet been placed in the water.","success_criteria":["A clear glass is visible and contains water to roughly 3/4 of its height.","A container of salt is visible near the glass.","No egg is visible inside the glass yet."],"failure_hints":["If the glass is too full, pour a little out so the water doesn''t overflow when you add the egg.","Slide the salt container into the frame so the assistant can see it."]},"simulation":{"observation":"A clear glass sits on the bench, three-quarters full of plain tap water. A small mound of salt and a spoon wait beside it.","tutor_prompts":["Before we add the egg, what do you think will happen when you drop it in?","What property of the water and the egg will determine whether it sinks or floats?"]}},{"id":"drop-egg","instruction":"Gently lower the egg into the water with your fingers or a spoon. Watch what happens.","checkpoint":{"expected_state":"The egg has been placed in the water and is resting on the bottom of the glass, fully submerged.","success_criteria":["The egg is visible inside the glass.","The egg is at or very near the bottom of the glass, not floating at the top.","The water level rose slightly and did not overflow."],"failure_hints":["If the egg is floating already, your water might already be salty — start over with fresh tap water.","If the egg is not visible, tilt the camera slightly so we can see the bottom of the glass."]},"simulation":{"observation":"The egg sinks slowly and settles on the bottom of the glass. It does not float.","tutor_prompts":["The egg sank. What does that tell you about the density of the egg compared to the water?","How could we change the water — without removing the egg — so that it might float instead?"]}},{"id":"add-salt","instruction":"Add one tablespoon of salt and stir gently until it dissolves. The egg should stay in the glass.","checkpoint":{"expected_state":"The egg is still in the glass and salt has been added. The water may look slightly cloudy or have a small amount of undissolved salt at the bottom.","success_criteria":["The egg is still inside the glass.","There is visible evidence that salt has been added or stirring is happening (cloudy water, salt grains, or a spoon in the glass).","Nothing has spilled out of the glass."],"failure_hints":["Stir more slowly so you don''t crack the egg with the spoon.","If the water is overflowing, scoop a little out before adding more salt."]},"simulation":{"observation":"The salt swirls into the water as you stir. The egg still rests on the bottom, but the water looks slightly cloudier.","tutor_prompts":["We added salt but the egg hasn''t moved. What does that tell us so far?","What do you think will happen as we keep adding more salt?"]}},{"id":"egg-floats","instruction":"Keep adding salt a tablespoon at a time and stirring, until the egg lifts off the bottom and floats.","checkpoint":{"expected_state":"The egg is floating somewhere above the bottom of the glass — either suspended in the middle or rising to the surface.","success_criteria":["The egg is visible and is no longer resting on the bottom of the glass.","There is clear space between the egg and the bottom of the glass.","The water is still in the glass (not spilled out)."],"failure_hints":["Keep going — add another tablespoon of salt and stir well until it dissolves.","Make sure the salt is actually dissolving, not just sitting on the bottom."]},"simulation":{"observation":"After several spoonfuls of salt, the egg begins to drift upward and finally hovers near the top of the water.","tutor_prompts":["The egg floats now even though we didn''t change the egg at all. What changed?","Imagine an ocean versus a lake — where would it be easier to float, and why?"]}}],"reflection":["Explain in your own words why the egg sank in fresh water but floated in salt water.","If you used twice as much water but the same amount of salt, would the egg still float? Why or why not?","Name a real-world place where this same effect matters."]}'::jsonb)
on conflict (id) do update
  set data = excluded.data,
      updated_at = now();
